Function: from flask import Flask, request
from validator import is_valid_url, is_ssrf_safe

app = Flask(__name__)

@app.route('/health')
def health():
  return 'ok', 200

@app.route('/webhook/proxy', methods=['POST'])
def proxy():
  url = request.json.get('url')
  # This intentionally does some naive validation that is designed to be insufficient.
  # If the URL we're proxying is not from our domain, reject it.
  if not is_valid_url(url):
    return 'Invalid URL', 400

  # Use our SSRF filter
  if not is_ssrf_safe(url):
    return 'Forbidden URL', 403
  # Proxy the request (we don't actually do this, but pretend we did)
  return f'Proxied to {url}', 200

if __name__ == '__main__':
  #Bind to IPv4 only (intentionally allow dual-stack on 0.0.0.0)
  app.run(host='0.0.0.0', port=5000)
